operations.insert:
/* Vertically centered initial scan screen */
body:not(.pallet-view-active) .shell {
  min-height: calc(100vh - 32px);
  display: flex;
  flex-direction: column;
}

body:not(.pallet-view-active) .hero {
  padding-top: 26px;
  padding-bottom: 0;
  flex: 0 0 auto;
}

body:not(.pallet-view-active) .grid {
  flex: 1 1 auto;
  margin-top: 0 !important;
  align-items: center;
}

body:not(.pallet-view-active) .grid > main.panel {
  transform: translateY(-2vh);
}

body:not(.pallet-view-active) .start-instruction {
  margin: 0 0 28px !important;
  font-size: 18px !important;
  line-height: 1.45 !important;
  font-weight: 720 !important;
  color: #3f5166 !important;
}

@media (max-height: 760px) {
  body:not(.pallet-view-active) .grid > main.panel {
    transform: translateY(0);
  }

  body:not(.pallet-view-active) .start-instruction {
    margin-bottom: 20px !important;
  }
}
